module RefModule (
    input clk,
    input reset,
    output reg [3:0] q
);

    // 4-bit binary counter with reset logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            q <= 0;
        end else begin
            q <= q + 1;
        end
    end

endmodule
